#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);

print header;

my $log_dir = '/path/to/log/directory';
my $logfile = param('logfile');

if (!defined $logfile || $logfile !~ /^\w+\.log$/) {
    print "<h1>Error: Invalid log file name</h1>";
    exit;
}

open(my $fh, "<", "$log_dir/$logfile") or die "Could not open '$logfile' $!";

print <<HTML;
<!DOCTYPE html>
<html>
<head>
    <title>Log Viewer - $logfile</title>
</head>
<body>
    <h1>$logfile</h1>
    <pre>
HTML

while (my $line = <$fh>) {
    print escapeHTML($line);
}

close $fh;

print <<HTML;
    </pre>
</body>
</html>
